import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';

function MovieRow({ title, movies = [] }) {
  return (
    <section className="section">
      <h2 className="section-title">{title}</h2>
      <div className="movies-row">
        {movies.map((movie) => (
          <Link
            key={movie._id}
            to={`/movie/${movie._id}`}
            className="movie-card"
            style={{ width: '220px', height: '320px' }}
          >
            <img src={movie.thumbnail} alt={movie.title} loading="lazy" />
            <div className="card-overlay">
              <div className="card-title">{movie.title}</div>
              <div className="card-meta">
                <span>{movie.year}</span>
                <span>•</span>
                <span className="card-rating">{movie.rating?.toFixed(1) || 'N/A'}</span>
              </div>
            </div>
          </Link>
        ))}
      </div>
    </section>
  );
}

export default function HomePage() {
  const { API } = useAuth();
  const [featured, setFeatured] = useState([]);
  const [trending, setTrending] = useState([]);
  const [genres, setGenres] = useState([]);
  const [genreMovies, setGenreMovies] = useState({});
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let mounted = true;
    setLoading(true);

    Promise.all([
      axios.get(`${API}/movies/featured`),
      axios.get(`${API}/movies/trending`),
      axios.get(`${API}/movies/genres`),
    ])
      .then(async ([f, t, g]) => {
        if (!mounted) return;
        setFeatured(f.data || []);
        setTrending(t.data || []);

        const genreList = (g.data || []).filter(genre => genre !== 'All').slice(0, 5);
        setGenres(genreList);

        const genreMoviesData = {};
        for (const genre of genreList) {
          try {
            const res = await axios.get(`${API}/movies`, {
              params: { genre, sort: 'rating', limit: 5 }
            });
            genreMoviesData[genre] = res.data.movies || [];
          } catch (err) {
            genreMoviesData[genre] = [];
          }
        }

        if (mounted) {
          setGenreMovies(genreMoviesData);
        }
      })
      .catch(() => {
        if (!mounted) return;
        setFeatured([]);
        setTrending([]);
        setGenres([]);
      })
      .finally(() => {
        if (mounted) {
          setLoading(false);
        }
      });

    return () => {
      mounted = false;
    };
  }, [API]);

  return (
    <main className="page" style={{ padding: '100px 24px 32px' }}>
      {loading ? (
        <div style={{ textAlign: 'center', padding: '40px' }}>Loading...</div>
      ) : (
        <>
          <MovieRow title="Featured" movies={featured} />
          <MovieRow title="Trending" movies={trending} />
          {genres.map(genre => (
            <MovieRow key={genre} title={genre} movies={genreMovies[genre] || []} />
          ))}
        </>
      )}
    </main>
  );
}
